def require(text: str, needle: str, label: str) -> None:
    if needle not in text:
        raise AssertionError(f"{label} missing expected snippet: {needle!r}")


def forbid(text: str, needle: str, label: str) -> None:
    if needle in text:
        raise AssertionError(f"{label} contains forbidden snippet: {needle!r}")


def require_order(text: str, before: str, after: str, label: str) -> None:
    before_index = text.find(before)
    after_index = text.find(after)
    if before_index < 0:
        raise AssertionError(f"{label} missing first snippet: {before!r}")
    if after_index < 0:
        raise AssertionError(f"{label} missing second snippet: {after!r}")
    if before_index >= after_index:
        raise AssertionError(f"{label} expected {before!r} before {after!r}")


def require_absent(text: str, needle: str, label: str) -> None:
    if needle in text:
        raise AssertionError(f"{label} contains unexpected snippet: {needle!r}")


